import{_ as s,o as t,c as a,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Tests","description":"","frontmatter":{"summary":"How to run tests locally (vitest) and when to use force/coverage modes","read_when":["Running or fixing tests"],"title":"Tests"},"headers":[],"relativePath":"reference/test.md","filePath":"reference/test.md","lastUpdated":null}'),n={name:"reference/test.md"};function o(r,e,l,c,d,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="tests" tabindex="-1"><a class="header-anchor" href="#tests">#</a> Tests</h1><ul><li><p>Full testing kit (suites, live, Docker): <a href="/docs/help/testing">Testing</a></p></li><li><p><code>pnpm test:force</code>: Kills any lingering gateway process holding the default control port, then runs the full Vitest suite with an isolated gateway port so server tests don’t collide with a running instance. Use this when a prior gateway run left port 18789 occupied.</p></li><li><p><code>pnpm test:coverage</code>: Runs Vitest with V8 coverage. Global thresholds are 70% lines/branches/functions/statements. Coverage excludes integration-heavy entrypoints (CLI wiring, gateway/telegram bridges, webchat static server) to keep the target focused on unit-testable logic.</p></li><li><p><code>pnpm test:e2e</code>: Runs gateway end-to-end smoke tests (multi-instance WS/HTTP/node pairing).</p></li><li><p><code>pnpm test:live</code>: Runs provider live tests (minimax/zai). Requires API keys and <code>LIVE=1</code> (or provider-specific <code>*_LIVE_TEST=1</code>) to unskip.</p></li></ul><h2 id="model-latency-bench-local-keys" tabindex="-1"><a class="header-anchor" href="#model-latency-bench-local-keys">#</a> Model latency bench (local keys)</h2><p>Script: <a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/bench-model.ts" target="_blank" rel="noreferrer"><code>scripts/bench-model.ts</code></a></p><p>Usage:</p><ul><li><code>source ~/.profile &amp;&amp; pnpm tsx scripts/bench-model.ts --runs 10</code></li><li>Optional env: <code>MINIMAX_API_KEY</code>, <code>MINIMAX_BASE_URL</code>, <code>MINIMAX_MODEL</code>, <code>ANTHROPIC_API_KEY</code></li><li>Default prompt: “Reply with a single word: ok. No punctuation or extra text.”</li></ul><p>Last run (2025-12-31, 20 runs):</p><ul><li>minimax median 1279ms (min 1114, max 2431)</li><li>opus median 2454ms (min 1224, max 3170)</li></ul><h2 id="onboarding-e2e-docker" tabindex="-1"><a class="header-anchor" href="#onboarding-e2e-docker">#</a> Onboarding E2E (Docker)</h2><p>Docker is optional; this is only needed for containerized onboarding smoke tests.</p><p>Full cold-start flow in a clean Linux container:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/e2e/onboard-docker.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This script drives the interactive wizard via a pseudo-tty, verifies config/workspace/session files, then starts the gateway and runs <code>opensoul health</code>.</p><h2 id="qr-import-smoke-docker" tabindex="-1"><a class="header-anchor" href="#qr-import-smoke-docker">#</a> QR import smoke (Docker)</h2><p>Ensures <code>qrcode-terminal</code> loads under Node 22+ in Docker:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:docker:qr</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',16)])])}const m=s(n,[["render",o]]);export{u as __pageData,m as default};
